function [thresholdDB, slopeEst, nRedos, timeSecs, ...    testContrast, interval, responses] = ...    mainRunAdd(initialConDB,...    durationFrames, ISI, ITI, targetContrast, ...    nTrials, s_files_order, condLabel, layerLabel, referenceCond, imgIndex)% [thresholdDB, slopeEst,nRedos, timeSecs, ...%		actualConDB, interval, responses,controlOrder,targetOrder] = ...%		  RunMask(control,target,nulls,...%			expType, controlConDB,initialConDB,targetLevel,...%			duration, ISI, ITI, targetCoh, ...%			bgClutT,imageClutsT, contrastDBT,nTrials);%%	Run the simultaneous masking experiment.  This subroutine% is called by DoSimon.%% Input:%		control:	quantized control image%		target:	quantized target image%		controlConDB:	control contrast%		initialConDB:	initial target contrast%		durationFrames: stimulus duration in frames% 	ISI: interstimulus interval in milliseconds% 	ITI: intertrial interval in milliseconds%% 8/25/97	ccc	Wrote it% Declare screen globalsglobal screenRectT winT nBits% Diagnostic switchesdiagnosticPlots = 0;diagnosticMsgs = 1;nBits = 8;% Read the text file into a cell array% fileID = fopen('s_files_order.txt', 'r');% s_files_order = textscan(fileID, '%s');% fclose(fileID);% Put initial test contrsat guess inside usable range% minTargetConDB = contrastDBT(1);% maxTargetConDB = contrastDBT(length(contrastDBT));% % if (initialConDB < minTargetConDB)%     initialConDB = minTargetConDB;%     showControl=0;% elseif (initialConDB > maxTargetConDB)%     initialConDB = maxTargetConDB;% % end% frameThresh = 50;nRealTrials = nTrials; % Number of trials recordednPracticeTrials = 2; % Number of practice trials (at intitial contrast)nTrials = nRealTrials + nPracticeTrials;% ===================================== %% Initialize PSI% ===================================== %% Psiparameters% Set up the threshold range for estimation ----> change% specify targetContrastreferenceIndex = log10(referenceCond);fprintf('referenceIndex - %f\n',referenceIndex);startpoint = find(round(targetContrast, 3) == round(referenceIndex, 3)); % specify startpoint of the rangefprintf('startpoint - %f\n',startpoint);if referenceCond == 1        minContrastdB = targetContrast(1);    maxContrastdB = targetContrast(40);    minThresdB = targetContrast(1);    maxThresdB = targetContrast(40);else    minContrastdB = targetContrast(startpoint+1);    maxContrastdB = targetContrast(startpoint+40);    minThresdB = targetContrast(startpoint+1);    maxThresdB = targetContrast(startpoint+40);end    thresStep = (maxThresdB - minThresdB)/39; % dB;% Set up the slope range for estimationminSlope=1;maxSlope=4;slopeStep=.25; % octave unitscohStep = (maxThresdB - minThresdB)/39;pcorr=0.86;		% percentage correct at thresholdmiss = 0.04;	% miss levelgamma = .5;		% Guessing factor. It is 0.5 for 2AFC% initialize Psi parametersPSIpar=PsiInit(minThresdB, maxThresdB, thresStep, ...    minSlope, maxSlope, slopeStep, minContrastdB, maxContrastdB, cohStep, ...    miss, gamma, pcorr);%% Run% Blank the screensScreen(winT,'FillRect',128,screenRectT);% LoadClut(winT,bgClutT,0,nBits);% Draw the fixation point.disp('Drawing fixation point ...');fixRect = [0 0 3 3];fixRect = CenterRect(fixRect,screenRectT);Screen('FillOval',winT, 0,fixRect);Screen('flip',winT);% Find correct control clut% disp('Finding masker CLUT ...');% [~, targetCluts] = FindBestCluts(...%     durationFrames, frameThresh, controlConDB, imageClutsT, contrastDBT, ...%     bgClutT);% % [~, nMC]=size(targetCluts);% targetCluts(1,:)=kron(ones(1,nMC/3),[255 0 0]);% beeper sound indicating the start of a rundisp('Ready to go, hit any button to start trials');Snd('Play',sin((0:2000)*0.25));Snd('Play',sin((0:2000)*0.4));Snd('Play',sin((0:2000)*0.25));try    KbWait;catch    fprintf('error occured on KB');end% Draw the fixation point.disp('Drawing fixation point');fixRect = [0 0 3 3];fixRect = CenterRect(fixRect,screenRectT);Screen(winT, 'FillOval', 0, fixRect);% ===================================== %% run trial by trial% ===================================== %startTime = GetSecs;nRedos = 0;HideCursor;% filterIndex = []; % desire index of filterfor i = 1:nTrials    Screen(winT,'FillRect',128,screenRectT);    % Get the recommended test intensity from PSI.    contIndex = PsiPlace(PSIpar);    fprintf('contIndex - %f\n',contIndex);    %contIndex = int8(contIndex);    testcon_temp = PSIpar.contRange(contIndex);    fprintf('conRange - %f\n',testcon_temp);    testcon_temp = 10.^testcon_temp; % log10 linear    fprintf('logLinear - %f\n',testcon_temp);    testcon_temp = round(testcon_temp,3); % round to 3 decimal places    testContrast(i) = testcon_temp;       % Get the file name without extension    [~, sfile_name, ~] = fileparts(s_files_order{imgIndex});        % change index to right string type    if testcon_temp == floor(testcon_temp) % Check if the value is an integer        testcon_temp = sprintf('%.1f', testcon_temp);    else        testcon_temp = regexprep(sprintf('%.4f', testcon_temp), '0*$', '');    end        % the corresponding stimulus image        if referenceCond ~= 1         refCond = regexprep(sprintf('%.4f', referenceCond), '0*$', '');        refCond = regexprep(refCond, '\.$', '.0');                    if condLabel == 3 % combined condition            reconimgFile = sprintf('./add/Layer%d/%s_pc1+pc2x%s.png', ...                               layerLabel, sfile_name, testcon_temp);            sourceimgFile = sprintf('./add/Layer%d/%s_pc1+pc2x%s.png', ...                                layerLabel, sfile_name, refCond);        else            reconimgFile = sprintf('./Layer%d/%s_pc%dx%s.png', ...                               layerLabel, sfile_name, condLabel, testcon_temp);            sourceimgFile = sprintf('./Layer%d/%s_pc%dx%s.png', ...                                layerLabel, sfile_name, condLabel, refCond);        end            else % ref -> original        if condLabel == 3            reconimgFile = sprintf('./add/Layer%d/%s_pc1+pc2x%s.png', ...                               layerLabel, sfile_name, testcon_temp);        else            reconimgFile = sprintf('./Layer%d/%s_pc%dx%s.png', ...                               layerLabel, sfile_name, condLabel, testcon_temp);        end        sourceimgFile = sprintf('./source_images/%s.png',sfile_name);     end        try        thisSource = imread(sourceimgFile, 'png');    catch        fprintf('error occured on reference - %s\n',sourceimgFile);    end    try        thisReImg = imread(reconimgFile, 'png');    catch        fprintf('error occured on tested - %s\n',reconimgFile);    end    thisSource = imresize(thisSource, [425 425]);    thisReImg = imresize(thisReImg, [425 425]);   % Loop until we do a satisfactory trial    while(1)        % Wait for the intertrial interval =====> change ITI for desire        WaitSecs(ITI/1000);        % Show the trial and get back which interval had target        interval(i) = mainPresentMonoStimulus(ISI,durationFrames,...            thisReImg,thisSource);        % Get observer response        responses(i) = GetResponse(interval(i));        if (responses(i) == 0)            Snd('Play',sin((0:4000)*0.1));        end        if (responses(i) == 1)            Snd('Play',sin((0:2000)*0.25));        end        if (responses(i) >= 0)            break;        end        if (responses(i) == -2)            % Do the abort thing here            thresholdConDB = -2000;            thresholdSd = -2000;            timeSecs=-1;            return;        end        nRedos = nRedos + 1;    end    % Update Psi's view of the world    if(i > nPracticeTrials)        [thresEst, slopeEst, PSIpar]=PsiUpdate(PSIpar, contIndex, responses(i));    else        thresEst=initialConDB;    end    if (diagnosticPlots == 1)        plotThres(i)=thresEst;        plotSlope(i)=slopeEst;    end    if (diagnosticMsgs)        fprintf('Threshold estimate is %g \n',thresEst);    	%		disp(sprintf('Desired/actual contrasts are %g,%g',...    	%			testContrastDB(i),actualContrastDB(i)));    endend% Get the threshold estimatethresholdDB = thresEst;thresholdSd = slopeEst;if (diagnosticMsgs)    fprintf('Threshold estimate is %g \n',thresholdDB);end% ImageNameOrder = nIndex;% Get elapsed timefinishTime=GetSecs;timeSecs = finishTime-startTime;